('11111111-0001-0001-0001-000000000001', 'PromptVault', ARRAY['ai','productivity'], '$12k/mo', '8.4k', 'reddit', 'https://reddit.com/r/SideProject/promptvault', '"I keep losing my best prompts in a Google Doc — would pay for something that auto-tags, ranks, and lets me share folders with my team. The dealbreaker is browser-side capture; ChatGPT/Claude tabs."', 'yes', 'simple', '2026-05-18 00:00:00+00'),
('11111111-0002-0002-0002-000000000002', 'Inbox Sentinel', ARRAY['productivity'], '$4.2k/mo', '2.1k', 'ih', 'https://indiehackers.com/inbox-sentinel', 'Sentiment + urgency overlay on Gmail. Indie dev cleared $4k MRR in 11 weeks. Mentions a pricing wall at $9 → $19 that doubled conversions.', 'yes', 'medium', '2026-05-17 00:00:00+00'),
('11111111-0003-0003-0003-000000000003', 'ReceiptParse', ARRAY['finance','ai'], NULL, NULL, 'pd', 'https://producthunt.com/posts/receiptparse', 'Small business owners asking for OCR + categorization that plugs into QuickBooks. Several said current tools require Zapier glue that breaks weekly.', 'maybe', 'complex', '2026-05-17 00:00:00+00'),
('11111111-0004-0004-0004-000000000004', 'FocusFrame', ARRAY['productivity','design'], '$2.8k/mo', '1.6k', 'reddit', 'https://reddit.com/r/SideProject/focusframe', '"Hide everything on the page except the article I''m reading. Pomodoro mode optional." Top comment: pays $5/mo, would pay $15.', 'yes', 'simple', '2026-05-16 00:00:00+00'),
('11111111-0005-0005-0005-000000000005', 'QueryRunner', ARRAY['devtools','data'], '$28k/mo', '4.2k', 'hn', 'https://news.ycombinator.com/queryrunner', 'DuckDB-in-browser for analysts. Founder posted a Show HN, hit #1 for 8h. Several enterprise inbound.', 'no', 'complex', '2026-05-16 00:00:00+00'),
