('11111111-0007-0007-0007-000000000007', 'Cohort Calculator', ARRAY['data','finance'], '$1.1k/mo', '340', 'ih', 'https://indiehackers.com/cohort-calculator', 'Tiny niche tool for D2C founders. Built in 2 weekends, $39 lifetime, 28 sales first week.', 'no', 'medium', '2026-05-15 00:00:00+00'),
('11111111-0008-0008-0008-000000000008', 'TabHerd', ARRAY['productivity'], '$6.5k/mo', '11.2k', 'pd', 'https://producthunt.com/posts/tabherd', 'Smart tab grouping by domain + AI summary. Reviewers complain about Chrome''s native grouping being clunky and not persistent across windows.', 'yes', 'medium', '2026-05-14 00:00:00+00'),
